// LOCAL REDACTION (no AI, no external call) — mirrors worker/redaction.py.
// Deterministic PII (phone, email, IBAN, birthdate-near-'geb.') is caught by a
// regex pack at confidence 1.0 and masked to stable placeholders. FAIL-CLOSED:
// when in doubt, mask. The ONLY text allowed past this node is the redacted text.
const raw = $json.ocr_text || '';
const found = [];
let text = raw;
let n = { TEL: 0, MAIL: 0, IBAN: 0, GEBURT: 0, NAME: 0 };

function mask(re, kind) {
  text = text.replace(re, (m) => {
    n[kind] += 1;
    const ph = `[${kind}_${n[kind]}]`;
    found.push({ kind, placeholder: ph, original_len: m.length });
    return ph;
  });
}

// Deterministic, confidence 1.0 — German patterns.
mask(/[\w.+-]+@[\w-]+\.[\w.-]+/g, 'MAIL');
mask(/\b(?:\+49|0)[\d\s\/-]{6,}\d/g, 'TEL');
mask(/\bDE\d{2}[\s]?(?:\d{4}[\s]?){4}\d{2}\b/g, 'IBAN');
// birthdate near 'geb.'
mask(/geb\.?\s*\d{1,2}\.\d{1,2}\.\d{2,4}/gi, 'GEBURT');
// A simple name guess: 'Firstname Lastname' before a comma/phone context.
// (In the MVP this is Presidio+spaCy NER, fail-closed above a threshold; here a
//  small heuristic stands in. LOCATION is deliberately NOT masked — on a board the
//  'locations' are the org's own name/town, not PII.)
mask(/\b(Frau|Herr)\s+[A-ZÄÖÜ][a-zäöüß]+/g, 'NAME');
mask(/\b[A-ZÄÖÜ][a-zäöüß]+\s+[A-ZÄÖÜ][a-zäöüß]+(?=,)/g, 'NAME');

return [{ json: {
  redacted_text: text,            // <-- the ONLY thing allowed to leave the box
  redactions_found: found.length, // count only; originals stay local
  redaction_kinds: n,
  // NOTE: we DO NOT pass `raw` forward. The boundary is enforced here.
  contains_at_symbol: text.includes('@'),  // sanity assert below
  contains_digits_run: /\d{6,}/.test(text)
}}];

// ASSERT the boundary held before anything is allowed to be 'sent to the LLM'.
// If any raw PII pattern survived, FAIL CLOSED — do not proceed.
const t = $json.redacted_text || '';
const leaks = [];
if (/[\w.+-]+@[\w-]+\.[\w.-]+/.test(t)) leaks.push('email');
if (/\b(?:\+49|0)[\d\s\/-]{6,}\d/.test(t)) leaks.push('phone');
if (/\bDE\d{2}/.test(t)) leaks.push('iban');
if (/geb\.?\s*\d/.test(t)) leaks.push('birthdate');
const safe = leaks.length === 0;
return [{ json: {
  redacted_text: t,
  redactions_found: $json.redactions_found,
  boundary_ok: safe,
  leaked_patterns: leaks,
  verdict: safe ? 'SAFE TO SEND TO LLM (redacted only)' : 'BLOCKED — raw PII detected, fail closed'
}}];
